  }
  return [{ json: { ...ctx, confirmAction: 'create_event', selectedSlot: slot, pending } }];
}

if (pending.step === 'awaiting_cancel_confirmation') {
  if (text === 'yes' || text === 'ya' || text === 'yeah' || text === 'yep') {
