    customer: ctx.customer,
    text: ctx.text,
    name: ctx.name,
    extracted: ctx.extracted,
    responseText: confirmMsg,
    pendingBooking: null,
    calendarEventId: result.eventId || result.id || null
  }
}];

const ctx = $('Handle Confirmation').item.json;

return [{
  json: {
    from: ctx.from,
    phoneNumberId: ctx.phoneNumberId,
    sessionKey: ctx.sessionKey,
    customerKey: ctx.customerKey,
    conversation: ctx.conversation,
    customer: ctx.customer,
    text: ctx.text,
    name: ctx.name,
    extracted: ctx.extracted,
    responseText: '? Your appointment has been successfully cancelled.\n\nWe hope to see you soon! To book a new appointment, just send us a message.',
    pendingBooking: null
  }
}];

const ctx = $('Parse Intent Response').item.json;

const defaultMsg = 'Hi! ?? I can help you with:\n\n?? *Book* an appointment\n?? *Reschedule* your appointment\n? *Cancel* your appointment\n\nWhat would you like to do?';

return [{
  json: {
    ...ctx,
    responseText: ctx.aiReply || defaultMsg,
    pendingBooking: ctx.pendingBooking
  }
}];

const item = $input.first().json;
const conversation = [...(item.conversation || [])];

conversation.push({ role: 'user', content: item.text, ts: Date.now() });
conversation.push({ role: 'assistant', content: item.responseText, ts: Date.now() });

if (conversation.length > 20) conversation.splice(0, conversation.length - 20);

const updatedCustomer = {
  ...(item.customer || {}),
  name: item.extracted?.name || item.name || item.customer?.name || '',
  phone: item.from,
  pendingBooking: item.pendingBooking || null,
  lastSeen: Date.now()
};

return [{
  json: {
    from: item.from,
    phoneNumberId: item.phoneNumberId,
    responseText: item.responseText,
    sessionKey: item.sessionKey,
    customerKey: item.customerKey,
    conversationJson: JSON.stringify(conversation),
    customerJson: JSON.stringify(updatedCustomer)
  }
}];
